// Define the scaling factor and byte order for KWh
const KWh_scalingFactor = 1; // Change this if the value needs to be scaled
const KWh_isByteSwapNeeded = false; // Set to true if low register comes first

if (msg.payload && msg.payload.length >= 2) {
    // Get the two 16-bit register values for KWh
    let reg1_KWh = msg.payload[0];
    let reg2_KWh = msg.payload[1];

    // Check if byte swapping is needed for KWh
    if (KWh_isByteSwapNeeded) {
        [reg1_KWh, reg2_KWh] = [reg2_KWh, reg1_KWh]; // Swap the registers
    }

    // Create a buffer for the float conversion
    const buffer = Buffer.alloc(4);

    // Write as big-endian 16-bit values
    buffer.writeUInt16BE(reg1_KWh, 0);
    buffer.writeUInt16BE(reg2_KWh, 2);

    // Read as big-endian float32 and apply scaling
    const TotalKWh = buffer.readFloatBE(0) * KWh_scalingFactor;

    msg.payload = {
        raw_registers: [reg1_KWh, reg2_KWh],
        Total_KWh: TotalKWh,
        unit: "Units",
        timestamp: new Date().toISOString()
    };

    return msg;
} else {
    node.error("Invalid payload received for KWh");
    return null;
}

