// Parse all float32 parameters from 28-register block
const regs = msg.payload;

function readFloat(regs, startIndex) {
    if (!regs || regs.length < startIndex + 2) return null;
    const reg1 = regs[startIndex];
    const reg2 = regs[startIndex + 1];
    const buffer = Buffer.alloc(4);
    buffer.writeUInt16BE(reg1, 0);
    buffer.writeUInt16BE(reg2, 2);
    return buffer.readFloatBE(0);
}

if (!Array.isArray(regs) || regs.length < 28) {
    node.error("Invalid or short payload received: " + JSON.stringify(regs));
    return null;
}

msg.payload = {
    Total_KWh:      readFloat(regs, 0),
    Total_Kvarh:    readFloat(regs, 6),
    ActivePower:    readFloat(regs, 14),
    Reactive_Power: readFloat(regs, 16),
    Apparent_Power: readFloat(regs, 18),
    Voltage_L_N:    readFloat(regs, 20),
    Current_:       readFloat(regs, 22),
    power_factor1:  readFloat(regs, 24),
    Freequency_:    readFloat(regs, 26),
    timestamp:      new Date().toISOString()
};

return msg;
